.tarjeta-interactiva {
  display: block;
  text-decoration: none;
  background: linear-gradient(135deg, #0a1f1a 0%, #073d2d 100%);
  border: 2px solid var(--c-ciencias);
  border-radius: 10px;
  padding: 22px 24px;
  margin: 22px 0;
  position: relative;
  overflow: hidden;
  transition: transform 0.18s, box-shadow 0.18s, border-color 0.18s;
  color: #e5f4ee;
}
.tarjeta-interactiva:hover {
  transform: translateY(-2px);
  box-shadow: 0 12px 28px rgba(15, 122, 92, 0.25);
  border-color: #6ee7b7;
}
.tarjeta-interactiva::before {
  content: '';
  position: absolute;
  top: 0;
  right: 0;
  width: 140px;
  height: 100%;
  background:
    radial-gradient(circle at 70% 30%, rgba(110, 231, 183, 0.18) 0%, transparent 60%),
    radial-gradient(circle at 90% 70%, rgba(244, 114, 182, 0.12) 0%, transparent 50%);
  pointer-events: none;
}


.tarjeta-interactiva .ti-descripcion strong { color: #6ee7b7; }
.tarjeta-interactiva .ti-cta {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  background: #34d399;
  color: #051410;
  padding: 9px 18px;
  border-radius: 6px;
  font-weight: 700;
  font-size: 14px;
  letter-spacing: 0.02em;
  transition: background 0.15s;
  position: relative;
}
.tarjeta-interactiva:hover .ti-cta {
  background: #6ee7b7;
}
.tarjeta-interactiva .ti-cta .flecha {
  transition: transform 0.15s;
}
.tarjeta-interactiva:hover .ti-cta .flecha {
  transform: translateX(3px);
}
.tarjeta-interactiva h4 {color: #fbbf24;}
.tarjeta-interactiva .ti-icono {font-size: 1.6rem;}

@media (max-width: 640px) {
  .tarjeta-interactiva { padding: 18px 18px; }
  .tarjeta-interactiva h4 { font-size: 17px; }
  .tarjeta-interactiva .ti-descripcion { font-size: 14px; }
}

