/* === TOOLTIP EN PANTALLA === */
.tooltip-palabra {
  position: relative;
  cursor: help;
  color: #0d3b66;
  border-bottom: 2px dotted #6ca0dc;
  padding: 2px 4px;
  border-radius: 3px;
  background-color: #f8f9fa;
  transition: all 0.3s ease;
}

.tooltip-palabra:hover,
.tooltip-palabra:focus {
  background-color: #e3f2fd;
}

.tooltip-texto {
  visibility: hidden;
  opacity: 0;
  width: 280px;
  background-color: #0d3b66;
  color: #fff;
  text-align: left;
  border-radius: 8px;
  padding: 12px 15px;
  position: absolute;
  z-index: 100;
  bottom: 130%;
  left: 50%;
  margin-left: -140px;
  font-size: 0.85em;
  line-height: 1.5;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.2);
  transition: opacity 0.3s, visibility 0.3s;
  font-weight: normal;
  white-space: normal;
  word-wrap: break-word;
  pointer-events: none;
}

.tooltip-texto::after {
  content: '';
  position: absolute;
  top: 100%;
  left: 50%;
  margin-left: -8px;
  border-width: 8px;
  border-style: solid;
  border-color: #0d3b66 transparent transparent transparent;
}

.tooltip-palabra:hover .tooltip-texto,
.tooltip-palabra:focus .tooltip-texto {
  visibility: visible;
  opacity: 1;
}

