/* ============================================
   29. ESTILOS PARA IMPRESIÓN / PDF
   ============================================ */

@media print {
  body {
    font-size: 11pt;
    line-height: 1.5;
    padding: 0;
    max-width: 100%;
  }

  /* Ocultar tooltips flotantes */
  .tooltip-texto {
    display: none !important;
  }

  /* Convertir tooltip-palabra a texto normal */
  .tooltip-palabra {
    border-bottom: none;
    background-color: transparent;
    cursor: default;
    color: inherit;
    padding: 0;
  }

  /* Mostrar números de notas al pie */
  .nota-numero {
    display: inline !important;
  }

  /* Mostrar glosario/notas al pie */
  .notas-al-pie {
    display: block !important;
    page-break-inside: avoid;
  }

  /* Evitar cortes de página en elementos importantes */
  .caja-nota,
  .caja-ejemplo,
  .caja-pasos,
  .caja-importante,
  .paso,
  .concepto,
  details {
    page-break-inside: avoid;
  }

  /* Encabezados no se quedan solos al final de página */
  h1, h2, h3 {
    page-break-after: avoid;
  }

  /* Ocultar elementos interactivos */
  .container,
  .container_caja,
  .iframe-container,
  .video-container {
    display: none !important;
  }

  /* Tablas legibles */
  .tabla-wrapper {
    overflow: visible;
    border: 1px solid #333;
    box-shadow: none;
  }

  .tabla-wrapper::after {
    display: none !important;
  }

  .tabla-wrapper table {
    min-width: auto;
  }

  /* Imágenes con borde sutil */
  .img-responsive,
  .img-responsive2 {
    box-shadow: none;
    border: 1px solid #ccc;
  }

  /* Enlaces visibles con URL */
  a {
    color: #000;
    text-decoration: underline;
  }

  a[href^="http"]::after {
    content: " (" attr(href) ")";
    font-size: 0.8em;
    color: #666;
  }

  /* Acordeones abiertos para impresión */
  details {
    border: 1px solid #333;
  }

  details[open] summary::before {
    transform: none;
  }

  summary {
    background-color: #f0f0f0 !important;
    color: #000 !important;
  }
}

