function(){
    var TEXTO_AVISO = '\u2194 Deslice la tabla horizontalmente para ver todas las columnas.';
    var pares = [];

    document.querySelectorAll('table').forEach(function(t){
      if(t.parentNode.classList.contains('tabla-scroll')) return;

      var cap = t.querySelector('caption');
      var etiqueta = (cap ? cap.textContent.trim() : 'Tabla de datos') +
                     ' (tabla desplazable horizontalmente)';

      var caja = document.createElement('div');
      caja.className = 'tabla-scroll';
      caja.setAttribute('role','region');
      caja.setAttribute('tabindex','0');
      caja.setAttribute('aria-label', etiqueta);

      t.parentNode.insertBefore(caja, t);
      caja.appendChild(t);

      var aviso = document.createElement('p');
      aviso.className = 'aviso-desliza';
      aviso.textContent = TEXTO_AVISO;
      aviso.style.display = 'none';
      caja.parentNode.insertBefore(aviso, caja.nextSibling);

      pares.push({caja:caja, aviso:aviso});
    });

    function actualizar(){
      pares.forEach(function(p){
        p.aviso.style.display =
          (p.caja.scrollWidth > p.caja.clientWidth + 2) ? 'block' : 'none';
      });
    }
    actualizar();

    var tm;
    window.addEventListener('resize', function(){
      clearTimeout(tm);
      tm = setTimeout(actualizar, 150);
    });
  })();

